  1	import {
  2	  ActionGroup,
  3	  Button,
  4	  Flex,
  5	  FlexItem,
  6	  Form,
  7	  FormGroup,
  8	  FormHelperText,
  9	  HelperText,
 10	  HelperTextItem,
 11	  MenuToggle,
 12	  MenuToggleElement,
 13	  NumberInput,
 14	  Select,
 15	  SelectList,
 16	  SelectOption,
 17	  TextArea,
 18	  TextInput,
 19	  Tooltip,
 20	  ValidatedOptions,
 21	} from '@patternfly/react-core';
 22	import { ExclamationCircleIcon } from '@patternfly/react-icons';
 23	import * as React from 'react';
 24	import { Trans, useTranslation } from 'react-i18next';
 25	import { useDomains } from '../hooks/useDomains';
 26	import { Query } from '../korrel8r/types';
 27	import { defaultSearch, Search, SearchType } from '../redux-actions';
 28	import { HelpPopover } from './HelpPopover';
 29	
 30	interface AdvancedSearchFormProps {
 31	  search: Search;
 32	  onSearch: (search: Search) => void;
 33	  onCancel: () => void;
 34	}
 35	
 36	export const AdvancedSearchForm: React.FC<AdvancedSearchFormProps> = ({
 37	  search,
 38	  onSearch,
 39	  onCancel,
 40	}) => {
 41	  const { t } = useTranslation('plugin__troubleshooting-panel-console-plugin');
 42	  const domains = useDomains();
 43	
 44	  const [queryStr, setQueryStr] = React.useState(search.queryStr);
 45	  const [searchType, setSearchType] = React.useState(search.searchType);
 46	  const [depth, setDepth] = React.useState(search.depth ?? defaultSearch.depth);
 47	  const [goal, setGoal] = React.useState(search.goal ?? '');
 48	
 49	  // Track whether fields have been edited by the user.
 50	  const [queryTouched, setQueryTouched] = React.useState(false);
 51	  const [goalTouched, setGoalTouched] = React.useState(false);
 52	
 53	  // Update state if search changes (e.g. Focus button pressed externally).
 54	  React.useEffect(() => {
 55	    setQueryStr(search.queryStr);
 56	    setSearchType(search.searchType);
 57	    onDepthChange(search.depth);
 58	    setGoal(search.goal ?? '');
 59	    setQueryTouched(false);
 60	    setGoalTouched(false);
 61	  }, [search.queryStr, search.searchType, search.depth, search.goal]);
 62	
 63	  const queryError = React.useMemo((): Error | null => {
 64	    try {
 65	      domains.queryToLink(Query.parse(queryStr?.trim()));
 66	      return null;
 67	    } catch (err) {
 68	      return err;
 69	    }
 70	  }, [queryStr, domains]);
 71	
 72	  const classError = React.useMemo((): Error | null => {
 73	    if (searchType !== SearchType.Goal) return null;
 74	    try {
 75	      domains.class(goal?.trim());
 76	      return null;
 77	    } catch (err) {
 78	      return err;
 79	    }
 80	  }, [goal, searchType, domains]);
 81	
 82	  // Show error styling only after the user has edited the field.
 83	  const validatedOption = (touched: boolean, err: Error | null) => {
 84	    if (!touched) return ValidatedOptions.default;
 85	    return err ? ValidatedOptions.error : ValidatedOptions.success;
 86	  };
 87	
 88	  const onDepthChange = (depth: number) =>
 89	    setDepth(Math.max(1, Math.min(10, depth ?? defaultSearch.depth)));
 90	
 91	  const isValid = React.useMemo(() => !queryError && !classError, [queryError, classError]);
 92	  const hasChanged = React.useMemo(
 93	    () =>
 94	      search.searchType !== searchType ||
 95	      search.queryStr !== queryStr ||
 96	      search.depth !== depth ||
 97	      search.goal !== goal,
 98	    [
 99	      search.searchType,
100	      search.queryStr,
101	      search.depth,
102	      search.goal,
103	      searchType,
104	      queryStr,
105	      depth,
106	      goal,
107	    ],
108	  );
109	
110	  const [searchTypeSelectOpen, setSearchTypeSelectOpen] = React.useState(false);
111	  const handleSubmit = () => {
112	    if (isValid && hasChanged) onSearch({ ...search, queryStr, searchType, depth, goal });
113	  };
114	  const handleEnter = (e: { key: string; shiftKey: boolean; preventDefault: () => void }) => {
115	    if (e.key === 'Enter' && !e.shiftKey) {
116	      e.preventDefault(); // Prevent newline
117	      handleSubmit();
118	    }
119	  };
120	
121	  return (
122	    <Form
123	      label={t('Advanced Search')}
124	      onSubmit={(e) => {
125	        e.preventDefault(); // Prevent page reload
126	        handleSubmit();
127	      }}
128	    >
129	      <FormGroup
130	        label={t('Start Query')}
131	        labelInfo={t('Select starting data')}
132	        hasNoPaddingTop={true}
133	        labelHelp={
134	          <HelpPopover>
135	            <Trans t={t}>
136	              <p>Query to select the starting data for the search.</p>
137	              <p>
138	                The <code>[Focus]</code> button fills in a query for the data shown in the main
139	                view. You can enter your own query.
140	              </p>
141	            </Trans>
142	          </HelpPopover>
143	        }
144	      >
145	        <Flex
146	          grow={{ default: 'grow' }}
147	          direction={{ default: 'row' }}
148	          alignItems={{ default: 'alignItemsCenter' }}
149	          spaceItems={{ default: 'spaceItemsSm' }}
150	        >
151	          <TextArea
152	            id="query-input"
153	            value={queryStr}
154	            onChange={(_event, value) => {
155	              setQueryStr(value);
156	              setQueryTouched(true);
157	            }}
158	            placeholder="domain:class:selector"
159	            onKeyDown={handleEnter}
160	            resizeOrientation="vertical"
161	            rows={2}
162	            validated={validatedOption(queryTouched, queryError)}
163	          />
164	        </Flex>
165	        {queryTouched && queryError && (
166	          <FormHelperText>
167	            <HelperText>
168	              <HelperTextItem icon={<ExclamationCircleIcon />} variant="error">
169	                <p>{queryError.message}</p>
170	              </HelperTextItem>
171	            </HelperText>
172	          </FormHelperText>
173	        )}
174	      </FormGroup>
175	
176	      <FormGroup
177	        label={t('Search Type')}
178	        labelInfo={t('Neighbours or Goal search')}
179	        hasNoPaddingTop={true}
180	        labelHelp={
181	          <HelpPopover>
182	            <Trans t={t}>
183	              <p>There are two types of correlation search:</p>
184	              <ul>
185	                <li>
186	                  <b>Neighbourhood</b>: Find all connected neighbours up to a maximum <i>depth</i>{' '}
187	                  (number of hops.)
188	                </li>
189	                <li>
190	                  <b>Goal</b>: Find paths to a selected <i>goal class</i>. Finds all shortest paths,
191	                  and some near-shortest paths.
192	                </li>
193	              </ul>
194	            </Trans>
195	          </HelpPopover>
196	        }
197	      >
198	        <Flex
199	          direction={{ default: 'row' }}
200	          alignItems={{ default: 'alignItemsCenter' }}
201	          spaceItems={{ default: 'spaceItemsSm' }}
202	        >
203	          <Select
204	            id="search-type"
205	            isOpen={searchTypeSelectOpen}
206	            selected={searchType}
207	            onSelect={(_e, value: string) => {
208	              setSearchType(value as SearchType);
209	              setSearchTypeSelectOpen(false);
210	            }}
211	            onOpenChange={setSearchTypeSelectOpen}
212	            toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
213	              <MenuToggle
214	                ref={toggleRef}
215	                onClick={() => setSearchTypeSelectOpen(!searchTypeSelectOpen)}
216	                isExpanded={searchTypeSelectOpen}
217	              >
218	                {searchType === SearchType.Goal ? t('Goals') : t('Neighbours')}
219	              </MenuToggle>
220	            )}
221	          >
222	            <SelectList>
223	              <SelectOption value={SearchType.Depth}>{t('Neighbours')}</SelectOption>
224	              <SelectOption value={SearchType.Goal}>{t('Goals')}</SelectOption>
225	            </SelectList>
226	          </Select>
227	          {searchType === SearchType.Goal ? (
228	            <FlexItem grow={{ default: 'grow' }}>
229	              <TextInput
230	                id="goal-class-input"
231	                value={goal ?? ''}
232	                placeholder="domain:classname"
233	                onChange={(_e, value) => {
234	                  setGoal(value);
235	                  setGoalTouched(true);
236	                }}
237	                validated={validatedOption(goalTouched, classError)}
238	              />
239	              {goalTouched && classError && (
240	                <FormHelperText>
241	                  <HelperText>
242	                    <HelperTextItem icon={<ExclamationCircleIcon />} variant="error">
243	                      {classError.message}
244	                    </HelperTextItem>
245	                  </HelperText>
246	                </FormHelperText>
247	              )}
248	            </FlexItem>
249	          ) : (
250	            <NumberInput
251	              id="depth-input"
252	              value={depth}
253	              unit={'hops'}
254	              min={1}
255	              max={10}
256	              onPlus={() => onDepthChange(depth + 1)}
257	              onMinus={() => onDepthChange(depth - 1)}
258	              onChange={(e) => onDepthChange(Number((e.target as HTMLInputElement).value))}
259	              widthChars={2}
260	            />
261	          )}
262	        </Flex>
263	      </FormGroup>
264	
265	      <ActionGroup>
266	        <Tooltip
267	          content={
268	            !isValid
269	              ? t('Fix validation errors before searching')
270	              : hasChanged
271	              ? t('Update the correlation graph')
272	              : t('Correlation graph already matches search')
273	          }
274	        >
275	          <Button
276	            type="submit"
277	            variant="primary"
278	            isAriaDisabled={!hasChanged || !isValid}
279	            size="sm"
280	          >
281	            {t('Search')}
282	          </Button>
283	        </Tooltip>
284	        <Button variant="secondary" onClick={onCancel}>
285	          {t('Cancel')}
286	        </Button>
287	      </ActionGroup>
288	    </Form>
289	  );
290	};

